61	func (g *ControlGuard) Admit(c frame.Control) error {
62		if !g.secure[c.ControlType] {
63			return nil
64		}
65		g.mu.Lock()
66		defer g.mu.Unlock()
67		ar, ok := g.guards[c.ControlType]
68		if !ok {
69			ar = &AntiReplay{}
70			g.guards[c.ControlType] = ar
71		}
72		if !ar.Accept(c.Seq) {
73			return ErrControlReplay
74		}
75		return nil
76	}
